1	import { DOMParser, Slice } from "@tiptap/pm/model";
2	import {
3	  EditorState,
4	  Plugin,
5	  PluginKey,
6	  PluginView,
7	  TextSelection,
8	} from "@tiptap/pm/state";
9	import { EditorView } from "@tiptap/pm/view";
10	
11	import { Block } from "../../blocks/defaultBlocks.js";
12	import type { BlockNoteEditor } from "../../editor/BlockNoteEditor.js";
13	import {
14	  createExtension,
15	  createStore,
16	} from "../../editor/BlockNoteExtension.js";
17	import { UiElementPosition } from "../../extensions-shared/UiElementPosition.js";
18	import {
19	  BlockSchema,
20	  InlineContentSchema,
21	  StyleSchema,
22	} from "../../schema/index.js";
23	import { getDraggableBlockFromElement } from "../getDraggableBlockFromElement.js";
24	import { dragStart, unsetDragImage } from "./dragging.js";
25	
26	export type SideMenuState<
27	  BSchema extends BlockSchema,
28	  I extends InlineContentSchema,
29	  S extends StyleSchema,
30	> = UiElementPosition & {
31	  // The block that the side menu is attached to.
32	  block: Block<BSchema, I, S>;
33	};
34	
35	const DISTANCE_TO_CONSIDER_EDITOR_BOUNDS = 250;
36	
37	function getBlockFromCoords(
38	  view: EditorView,
39	  coords: { left: number; top: number },
40	  adjustForColumns = true,
41	) {
42	  const elements = view.root.elementsFromPoint(coords.left, coords.top);
43	
44	  for (const element of elements) {
45	    if (!view.dom.contains(element)) {
46	      // probably a ui overlay like formatting toolbar etc
47	      continue;
48	    }
49	    if (adjustForColumns) {
50	      const column = element.closest("[data-node-type=columnList]");
51	      if (column) {
52	        return getBlockFromCoords(
53	          view,
54	          {
55	            // TODO can we do better than this?
56	            left: coords.left + 50, // bit hacky, but if we're inside a column, offset x position to right to account for the width of sidemenu itself
57	            top: coords.top,
58	          },
59	          false,
60	        );
61	      }
62	    }
63	    return getDraggableBlockFromElement(element, view);
64	  }
65	  return undefined;
66	}
67	
68	function getBlockFromMousePos(
69	  mousePos: {
70	    x: number;
71	    y: number;
72	  },
73	  view: EditorView,
74	): { node: HTMLElement; id: string } | undefined {
75	  // Editor itself may have padding or other styling which affects
76	  // size/position, so we get the boundingRect of the first child (i.e. the
77	  // blockGroup that wraps all blocks in the editor) for more accurate side
78	  // menu placement.
79	  if (!view.dom.firstChild) {
80	    return;
81	  }
82	
83	  const editorBoundingBox = (
84	    view.dom.firstChild as HTMLElement
85	  ).getBoundingClientRect();
86	
87	  // Gets block at mouse cursor's position.
88	  const coords = {
89	    // Clamps the x position to the editor's bounding box.
90	    left: Math.min(
91	      Math.max(editorBoundingBox.left + 10, mousePos.x),
92	      editorBoundingBox.right - 10,
93	    ),
94	    top: mousePos.y,
95	  };
96	
97	  const referenceBlock = getBlockFromCoords(view, coords);
98	
99	  if (!referenceBlock) {
100	    // could not find the reference block
101	    return undefined;
102	  }
103	
104	  /**
105	   * Because blocks may be nested, we need to check the right edge of the parent block:
106	   * ```
107	   * | BlockA        |
108	   * x | BlockB     y|
109	   * ```
110	   * Hovering at position x (left edge of BlockB) would return BlockA.
111	   * Instead, we check at position y (right edge of BlockA) to correctly identify BlockB.
112	   */
113	  const referenceBlocksBoundingBox =
114	    referenceBlock.node.getBoundingClientRect();
115	  return getBlockFromCoords(
116	    view,
117	    {
118	      left: referenceBlocksBoundingBox.right - 10,
119	      top: mousePos.y,
120	    },
121	    false,
122	  );
123	}
124	
125	/**
126	 * With the sidemenu plugin we can position a menu next to a hovered block.
127	 */
128	export class SideMenuView<
129	  BSchema extends BlockSchema,
130	  I extends InlineContentSchema,
131	  S extends StyleSchema,
132	> implements PluginView
133	{
134	  public state?: SideMenuState<BSchema, I, S>;
135	  public readonly emitUpdate: (state: SideMenuState<BSchema, I, S>) => void;
136	
137	  private mousePos: { x: number; y: number } | undefined;
138	
139	  private hoveredBlock: HTMLElement | undefined;
140	
141	  public menuFrozen = false;
142	
143	  public isDragOrigin = false;
144	
145	  constructor(
146	    private readonly editor: BlockNoteEditor<BSchema, I, S>,
147	    private readonly pmView: EditorView,
148	    emitUpdate: (state: SideMenuState<BSchema, I, S>) => void,
149	  ) {
150	    this.emitUpdate = () => {
151	      if (!this.state) {
152	        throw new Error("Attempting to update uninitialized side menu");
153	      }
154	
155	      emitUpdate(this.state);
156	    };
157	
158	    this.pmView.root.addEventListener(
159	      "dragstart",
160	      this.onDragStart as EventListener,
161	    );
162	    this.pmView.root.addEventListener(
163	      "dragover",
164	      this.onDragOver as EventListener,
165	    );
166	    this.pmView.root.addEventListener(
167	      "drop",
168	      this.onDrop as EventListener,
169	      true,
170	    );
171	    this.pmView.root.addEventListener(
172	      "dragend",
173	      this.onDragEnd as EventListener,
174	      true,
175	    );
176	
177	    // Shows or updates menu position whenever the cursor moves, if the menu isn't frozen.
178	    this.pmView.root.addEventListener(
179	      "mousemove",
180	      this.onMouseMove as EventListener,
181	      true,
182	    );
183	
184	    // Hides and unfreezes the menu whenever the user presses a key.
185	    this.pmView.root.addEventListener(
186	      "keydown",
187	      this.onKeyDown as EventListener,
188	      true,
189	    );
190	  }
191	
192	  updateState = (state: SideMenuState<BSchema, I, S>) => {
193	    this.state = state;
194	    this.emitUpdate(this.state);
195	  };
196	
197	  updateStateFromMousePos = () => {
198	    if (this.menuFrozen || !this.mousePos) {
199	      return;
200	    }
201	
202	    const closestEditor = this.findClosestEditorElement({
203	      clientX: this.mousePos.x,
204	      clientY: this.mousePos.y,
205	    });
206	
207	    if (
208	      closestEditor?.element !== this.pmView.dom ||
209	      closestEditor.distance > DISTANCE_TO_CONSIDER_EDITOR_BOUNDS
210	    ) {
211	      if (this.state?.show) {
212	        this.state.show = false;
213	        this.updateState(this.state);
214	      }
215	      return;
216	    }
217	
218	    const block = getBlockFromMousePos(this.mousePos, this.pmView);
219	
220	    // Closes the menu if the mouse cursor is beyond the editor vertically.
221	    if (!block || !this.editor.isEditable) {
222	      if (this.state?.show) {
223	        this.state.show = false;
224	        this.updateState(this.state);
225	      }
226	
227	      return;
228	    }
229	
230	    // Doesn't update if the menu is already open and the mouse cursor is still hovering the same block.
231	    if (
232	      this.state?.show &&
233	      this.hoveredBlock?.hasAttribute("data-id") &&
234	      this.hoveredBlock?.getAttribute("data-id") === block.id
235	    ) {
236	      return;
237	    }
238	
239	    this.hoveredBlock = block.node;
240	
241	    // Shows or updates elements.
242	    if (this.editor.isEditable) {
243	      const blockContentBoundingBox = block.node.getBoundingClientRect();
244	      const column = block.node.closest("[data-node-type=column]");
245	      this.state = {
246	        show: true,
247	        referencePos: new DOMRect(
248	          column
249	            ? // We take the first child as column elements have some default
250	              // padding. This is a little weird since this child element will
251	              // be the first block, but since it's always non-nested and we
252	              // only take the x coordinate, it's ok.
253	              column.firstElementChild!.getBoundingClientRect().x
254	            : (
255	                this.pmView.dom.firstChild as HTMLElement
256	              ).getBoundingClientRect().x,
257	          blockContentBoundingBox.y,
258	          blockContentBoundingBox.width,
259	          blockContentBoundingBox.height,
260	        ),
261	        block: this.editor.getBlock(
262	          this.hoveredBlock!.getAttribute("data-id")!,
263	        )!,
264	      };
265	      this.updateState(this.state);
266	    }
267	  };
268	
269	  /**
270	   * If a block is being dragged, ProseMirror usually gets the context of what's
271	   * being dragged from `view.dragging`, which is automatically set when a
272	   * `dragstart` event fires in the editor. However, if the user tries to drag
273	   * and drop blocks between multiple editors, only the one in which the drag
274	   * began has that context, so we need to set it on the others manually. This
275	   * ensures that PM always drops the blocks in between other blocks, and not
276	   * inside them.
277	   *
278	   * After the `dragstart` event fires on the drag handle, it sets
279	   * `blocknote/html` data on the clipboard. This handler fires right after,
280	   * parsing the `blocknote/html` data into nodes and setting them on
281	   * `view.dragging`.
282	   *
283	   * Note: Setting `view.dragging` on `dragover` would be better as the user
284	   * could then drag between editors in different windows, but you can only
285	   * access `dataTransfer` contents on `dragstart` and `drop` events.
286	   */
287	  onDragStart = (event: DragEvent) => {
288	    const html = event.dataTransfer?.getData("blocknote/html");
289	    if (!html) {
290	      return;
291	    }
292	
293	    if (this.pmView.dragging) {
294	      // already dragging, so no-op
295	      return;
296	    }
297	
298	    const element = document.createElement("div");
299	    element.innerHTML = html;
300	
301	    const parser = DOMParser.fromSchema(this.pmView.state.schema);
302	    const node = parser.parse(element, {
303	      topNode: this.pmView.state.schema.nodes["blockGroup"].create(),
304	    });
305	
306	    this.pmView.dragging = {
307	      slice: new Slice(node.content, 0, 0),
308	      move: true,
309	    };
310	  };
311	
312	  /**
313	   * Finds the closest editor visually to the given coordinates
314	   */
315	  private findClosestEditorElement = (coords: {
316	    clientX: number;
317	    clientY: number;
318	  }) => {
319	    // Get all editor elements in the document
320	    const editors = Array.from(this.pmView.root.querySelectorAll(".bn-editor"));
321	
322	    if (editors.length === 0) {
323	      return null;
324	    }
325	
326	    // Find the editor with the smallest distance to the coordinates
327	    let closestEditor = editors[0];
328	    let minDistance = Number.MAX_VALUE;
329	
330	    editors.forEach((editor) => {
331	      const rect = editor
332	        .querySelector(".bn-block-group")!
333	        .getBoundingClientRect();
334	
335	      const distanceX =
336	        coords.clientX < rect.left
337	          ? rect.left - coords.clientX
338	          : coords.clientX > rect.right
339	            ? coords.clientX - rect.right
340	            : 0;
341	
342	      const distanceY =
343	        coords.clientY < rect.top
344	          ? rect.top - coords.clientY
345	          : coords.clientY > rect.bottom
346	            ? coords.clientY - rect.bottom
347	            : 0;
348	
349	      const distance = Math.sqrt(
350	        Math.pow(distanceX, 2) + Math.pow(distanceY, 2),
351	      );
352	
353	      if (distance < minDistance) {
354	        minDistance = distance;
355	        closestEditor = editor;
356	      }
357	    });
358	
359	    return {
360	      element: closestEditor,
361	      distance: minDistance,
362	    };
363	  };
364	
365	  /**
366	   * This dragover event handler listens at the document level,
367	   * and is trying to handle dragover events for all editors.
368	   *
369	   * It specifically is trying to handle the following cases:
370	   *  - If the dragover event is within the bounds of any editor, then it does nothing
371	   *  - If the dragover event is outside the bounds of any editor, but close enough (within DISTANCE_TO_CONSIDER_EDITOR_BOUNDS) to the closest editor,
372	   *    then it dispatches a synthetic dragover event to the closest editor (which will trigger the drop-cursor to be shown on that editor)
373	   *  - If the dragover event is outside the bounds of the current editor, then it will dispatch a synthetic dragleave event to the current editor
374	   *    (which will trigger the drop-cursor to be removed from the current editor)
375	   *
376	   * The synthetic event is a necessary evil because we do not control prosemirror-dropcursor to be able to show the drop-cursor within the range we want
377	   */
378	  onDragOver = (event: DragEvent) => {
379	    if ((event as any).synthetic) {
380	      return;
381	    }
382	
383	    // Relevance gate: Only handle drags that belong to BlockNote
384	    // This prevents interference with external drag-and-drop libraries
385	    // by avoiding calls to closeDropCursor() for non-BlockNote drags
386	    const isBlockNoteDrag =
387	      this.pmView.dragging !== null ||
388	      this.isDragOrigin ||
389	      event.dataTransfer?.types.includes("blocknote/html") ||
390	      (event.target instanceof Node && this.pmView.dom.contains(event.target));
391	
392	    if (!isBlockNoteDrag) {
393	      // Not a BlockNote-related drag, return early without any processing
394	      return;
395	    }
396	
397	    const dragEventContext = this.getDragEventContext(event);
398	
399	    if (!dragEventContext || !dragEventContext.isDropPoint) {
400	      // This is not a drag event that we are interested in
401	      // so, we close the drop-cursor
402	      this.closeDropCursor();
403	      return;
404	    }
405	
406	    if (
407	      dragEventContext.isDropPoint &&
408	      !dragEventContext.isDropWithinEditorBounds
409	    ) {
410	      // we are the drop point, but the drag over event is not within the bounds of this editor instance
411	      // so, we need to dispatch an event that is in the bounds of this editor instance
412	      this.dispatchSyntheticEvent(event);
413	    }
414	  };
415	
416	  /**
417	   * Closes the drop-cursor for the current editor
418	   */
419	  private closeDropCursor = () => {
420	    const evt = new Event("dragleave", { bubbles: false });
421	    // It needs to be synthetic, so we don't accidentally think it is a real dragend event
422	    (evt as any).synthetic = true;
423	    // We dispatch the event to the current editor, so that the drop-cursor is removed for it
424	    this.pmView.dom.dispatchEvent(evt);
425	  };
426	
427	  /**
428	   * It is surprisingly difficult to determine the information we need to know about a drag event
429	   *
430	   * This function is trying to determine the following:
431	   *  - Whether the current editor instance is the drop point
432	   *  - Whether the current editor instance is the drag origin
433	   *  - Whether the drop event is within the bounds of the current editor instance
434	   */
435	  getDragEventContext = (event: DragEvent) => {
436	    // Relevance gate: Only handle drags that belong to BlockNote
437	    // Check if at least one of the following is true:
438	    // 1. ProseMirror drag started in an editor
439	    // 2. Side menu drag
440	    // 3. BlockNote-specific data type in the drag
441	    // 4. (optional stricter mode) Event target is inside this editor
442	    const isBlockNoteDrag =
443	      this.pmView.dragging !== null ||
444	      this.isDragOrigin ||
445	      event.dataTransfer?.types.includes("blocknote/html") ||
446	      (event.target instanceof Node && this.pmView.dom.contains(event.target));
447	
448	    if (!isBlockNoteDrag) {
449	      // Not a BlockNote-related drag, return early
450	      return undefined;
451	    }
452	
453	    // We need to check if there is text content that is being dragged (select some text & just drag it)
454	    const textContentIsBeingDragged =
455	      !event.dataTransfer?.types.includes("blocknote/html") &&
456	      !!this.pmView.dragging;
457	    // This is the side menu drag from this plugin
458	    const sideMenuIsBeingDragged = !!this.isDragOrigin;
459	    // Tells us that the current editor instance has a drag ongoing (either text or side menu)
460	    const isDragOrigin = textContentIsBeingDragged || sideMenuIsBeingDragged;
461	
462	    // Tells us which editor instance is the closest to the drag event (whether or not it is actually reasonably close)
463	    const closestEditor = this.findClosestEditorElement(event);
464	
465	    // We arbitrarily decide how far is "too far" from the closest editor to be considered a drop point
466	    if (
467	      !closestEditor ||
468	      closestEditor.distance > DISTANCE_TO_CONSIDER_EDITOR_BOUNDS
469	    ) {
470	      // we are too far from the closest editor, or no editor was found
471	      return undefined;
472	    }
473	
474	    // We check if the closest editor is the same as the current editor instance (which is the drop point)
475	    const isDropPoint = closestEditor.element === this.pmView.dom;
476	    // We check if the current editor instance is the same as the editor instance that the drag event is happening within
477	    const isDropWithinEditorBounds =
478	      isDropPoint && closestEditor.distance === 0;
479	
480	    // We never want to handle drop events that are not related to us
481	    if (!isDropPoint && !isDragOrigin) {
482	      // we are not the drop point or drag origin, so not relevant to us
483	      return undefined;
484	    }
485	
486	    return {
487	      isDropPoint,
488	      isDropWithinEditorBounds,
489	      isDragOrigin,
490	    };
491	  };
492	
493	  /**
494	   * The drop event handler listens at the document level,
495	   * and handles drop events for all editors.
496	   *
497	   * It specifically handles the following cases:
498	   *  - If we are both the drag origin and drop point:
499	   *    - Let normal drop handling take over
500	   *  - If we are the drop point but not the drag origin:
501	   *    - Collapse selection to prevent PM from deleting unrelated content
502	   *    - If drop event is outside our editor bounds, dispatch synthetic drop event to our editor
503	   *  - If we are the drag origin but not the drop point:
504	   *    - Delete the dragged content from our editor after a delay
505	   */
506	  onDrop = (event: DragEvent) => {
507	    if ((event as any).synthetic) {
508	      return;
509	    }
510	
511	    // Relevance gate: Only handle drags that belong to BlockNote
512	    // This prevents interference with external drag-and-drop libraries
513	    const isBlockNoteDrag =
514	      this.pmView.dragging !== null ||
515	      this.isDragOrigin ||
516	      event.dataTransfer?.types.includes("blocknote/html") ||
517	      (event.target instanceof Node && this.pmView.dom.contains(event.target));
518	
519	    if (!isBlockNoteDrag) {
520	      // Not a BlockNote-related drag, return early without any processing
521	      return;
522	    }
523	
524	    const context = this.getDragEventContext(event);
525	    if (!context) {
526	      this.closeDropCursor();
527	      // This is not a drag event that we are interested in
528	      return;
529	    }
530	    const { isDropPoint, isDropWithinEditorBounds, isDragOrigin } = context;
531	
532	    if (!isDropWithinEditorBounds && isDropPoint) {
533	      // Any time that the drop event is outside of the editor bounds (but still close to an editor instance)
534	      // We dispatch a synthetic event that is in the bounds of the editor instance, to have the correct drop point
535	      this.dispatchSyntheticEvent(event);
536	    }
537	
538	    if (isDropPoint) {
539	      // The current instance is the drop point
540	
541	      if (this.pmView.dragging) {
542	        // Do not collapse selection when text content is being dragged
543	        return;
544	      }
545	      // Because the editor selection is unrelated to the dragged content, we
546	      // don't want PM to delete its content. Therefore, we collapse the
547	      // selection.
548	      this.pmView.dispatch(
549	        this.pmView.state.tr.setSelection(
550	          TextSelection.create(
551	            this.pmView.state.tr.doc,
552	            this.pmView.state.tr.selection.anchor,
553	          ),
554	        ),
555	      );
556	      return;
557	    } else if (isDragOrigin) {
558	      // The current instance is the drag origin, but not the drop point
559	      // our content got dropped somewhere else
560	
561	      // Because the editor from which the block originates doesn't get a drop
562	      // event on it, PM doesn't delete its selected content. Therefore, we
563	      // need to do so manually.
564	      //
565	      // Note: Deleting the selected content from the editor from which the
566	      // block originates, may change its height. This can cause the position of
567	      // the editor in which the block is being dropping to shift, before it
568	      // can handle the drop event. That in turn can cause the drop to happen
569	      // somewhere other than the user intended. To get around this, we delay
570	      // deleting the selected content until all editors have had the chance to
571	      // handle the event.
572	      setTimeout(
573	        () => this.pmView.dispatch(this.pmView.state.tr.deleteSelection()),
574	        0,
575	      );
576	      return;
577	    }
578	  };
579	
580	  onDragEnd = (event: DragEvent) => {
581	    if ((event as any).synthetic) {
582	      return;
583	    }
584	    // When the user starts dragging a block, `view.dragging` is set on all
585	    // BlockNote editors. However, when the drag ends, only the editor that the
586	    // drag originated in automatically clears `view.dragging`. Therefore, we
587	    // have to manually clear it on all editors.
588	    this.pmView.dragging = null;
589	  };
590	
591	  onKeyDown = (_event: KeyboardEvent) => {
592	    if (this.state?.show && this.editor.isFocused()) {
593	      // Typing in editor should hide side menu
594	      this.state.show = false;
595	      this.emitUpdate(this.state);
596	    }
597	  };
598	
599	  onMouseMove = (event: MouseEvent) => {
600	    if (this.menuFrozen) {
601	      return;
602	    }
603	
604	    this.mousePos = { x: event.clientX, y: event.clientY };
605	
606	    // We want the full area of the editor to check if the cursor is hovering
607	    // above it though.
608	    const editorOuterBoundingBox = this.pmView.dom.getBoundingClientRect();
609	    const cursorWithinEditor =
610	      this.mousePos.x > editorOuterBoundingBox.left &&
611	      this.mousePos.x < editorOuterBoundingBox.right &&
612	      this.mousePos.y > editorOuterBoundingBox.top &&
613	      this.mousePos.y < editorOuterBoundingBox.bottom;
614	
615	    // TODO: remove parentElement, but then we need to remove padding from boundingbox or find a different solution
616	    const editorWrapper = this.pmView.dom!.parentElement!;
617	
618	    // Doesn't update if the mouse hovers an element that's over the editor but
619	    // isn't a part of it or the side menu.
620	    if (
621	      // Cursor is within the editor area
622	      cursorWithinEditor &&
623	      // An element is hovered
624	      event &&
625	      event.target &&
626	      // Element is outside the editor
627	      !(
628	        editorWrapper === event.target ||
629	        editorWrapper.contains(event.target as HTMLElement)
630	      )
631	    ) {
632	      if (this.state?.show) {
633	        this.state.show = false;
634	        this.emitUpdate(this.state);
635	      }
636	
637	      return;
638	    }
639	
640	    this.updateStateFromMousePos();
641	  };
642	
643	  private dispatchSyntheticEvent(event: DragEvent) {
644	    const evt = new Event(event.type as "dragover", event) as any;
645	    const dropPointBoundingBox = (
646	      this.pmView.dom.firstChild as HTMLElement
647	    ).getBoundingClientRect();
648	    evt.clientX = event.clientX;
649	    evt.clientY = event.clientY;
650	
651	    evt.clientX = Math.min(
652	      Math.max(event.clientX, dropPointBoundingBox.left),
653	      dropPointBoundingBox.left + dropPointBoundingBox.width,
654	    );
655	    evt.clientY = Math.min(
656	      Math.max(event.clientY, dropPointBoundingBox.top),
657	      dropPointBoundingBox.top + dropPointBoundingBox.height,
658	    );
659	
660	    evt.dataTransfer = event.dataTransfer;
661	    evt.preventDefault = () => event.preventDefault();
662	    evt.synthetic = true; // prevent recursion
663	    this.pmView.dom.dispatchEvent(evt);
664	  }
665	
666	  // Needed in cases where the editor state updates without the mouse cursor
667	  // moving, as some state updates can require a side menu update. For example,
668	  // adding a button to the side menu which removes the block can cause the
669	  // block below to jump up into the place of the removed block when clicked,
670	  // allowing the user to click the button again without moving the cursor. This
671	  // would otherwise not update the side menu, and so clicking the button again
672	  // would attempt to remove the same block again, causing an error.
673	  update(_view: EditorView, prevState: EditorState) {
674	    const docChanged = !prevState.doc.eq(this.pmView.state.doc);
675	    if (docChanged && this.state?.show) {
676	      this.updateStateFromMousePos();
677	    }
678	  }
679	
680	  destroy() {
681	    if (this.state?.show) {
682	      this.state.show = false;
683	      this.emitUpdate(this.state);
684	    }
685	    this.pmView.root.removeEventListener(
686	      "mousemove",
687	      this.onMouseMove as EventListener,
688	      true,
689	    );
690	    this.pmView.root.removeEventListener(
691	      "dragstart",
692	      this.onDragStart as EventListener,
693	    );
694	    this.pmView.root.removeEventListener(
695	      "dragover",
696	      this.onDragOver as EventListener,
697	    );
698	    this.pmView.root.removeEventListener(
699	      "drop",
700	      this.onDrop as EventListener,
701	      true,
702	    );
703	    this.pmView.root.removeEventListener(
704	      "dragend",
705	      this.onDragEnd as EventListener,
706	      true,
707	    );
708	    this.pmView.root.removeEventListener(
709	      "keydown",
710	      this.onKeyDown as EventListener,
711	      true,
712	    );
713	  }
714	}
715	
716	export const sideMenuPluginKey = new PluginKey("SideMenuPlugin");
717	
718	export const SideMenuExtension = createExtension(({ editor }) => {
719	  let view: SideMenuView<any, any, any> | undefined;
720	  const store = createStore<SideMenuState<any, any, any> | undefined>(
721	    undefined,
722	  );
723	
724	  return {
725	    key: "sideMenu",
726	    store,
727	    prosemirrorPlugins: [
728	      new Plugin({
729	        key: sideMenuPluginKey,
730	        view: (editorView) => {
731	          view = new SideMenuView(editor, editorView, (state) => {
732	            // TODO: Without spreading the state, in some cases like toggling
733	            // `show`, this doesn't trigger an update.
734	            store.setState({ ...state });
735	          });
736	          return view;
737	        },
738	      }),
739	    ],
740	
741	    /**
742	     * Handles drag & drop events for blocks.
743	     */
744	    blockDragStart(
745	      event: { dataTransfer: DataTransfer | null; clientY: number },
746	      block: Block<any, any, any>,
747	    ) {
748	      if (view) {
749	        view.isDragOrigin = true;
750	      }
751	      dragStart(event, block, editor);
752	    },
753	
754	    /**
755	     * Handles drag & drop events for blocks.
756	     */
757	    blockDragEnd() {
758	      unsetDragImage(editor.prosemirrorView.root);
759	      if (view) {
760	        view.isDragOrigin = false;
761	      }
762	
763	      editor.blur();
764	    },
765	
766	    /**
767	     * Freezes the side menu. When frozen, the side menu will stay
768	     * attached to the same block regardless of which block is hovered by the
769	     * mouse cursor.
770	     */
771	    freezeMenu() {
772	      view!.menuFrozen = true;
773	      view!.state!.show = true;
774	      view!.emitUpdate(view!.state!);
775	    },
776	
777	    /**
778	     * Unfreezes the side menu. When frozen, the side menu will stay
779	     * attached to the same block regardless of which block is hovered by the
780	     * mouse cursor.
781	     */
782	    unfreezeMenu() {
783	      view!.menuFrozen = false;
784	      view!.state!.show = false;
785	      view!.emitUpdate(view!.state!);
786	    },
787	  } as const;
788	});
