404	                          from: firstChildBlockInfo.bnBlock.beforePos,
405	                          to: firstChildBlockInfo.bnBlock.afterPos,
406	                        },
407	                  )
408	                  // Appends inline content from child block if possible.
409	                  .insertContentAt(
410	                    state.selection.from,
411	                    firstChildBlockHasInlineContent && blockHasInlineContent
412	                      ? firstChildBlockContent.content
413	                      : null,
414	                  )
415	                  .setTextSelection(state.selection.from)
416	                  .scrollIntoView()
417	                  .run()
418	              );
419	            }
420	
421	            return false;
422	          }),
423	        // Merges block with the next one (at the same nesting level or lower),
424	        // if one exists, the block has no children, and the selection is at the
425	        // end of the block.
426	        () =>
427	          commands.command(({ state }) => {
428	            const blockInfo = getBlockInfoFromSelection(state);
429	            if (!blockInfo.isBlockContainer) {
430	              return false;
431	            }
432	            const { bnBlock: blockContainer, blockContent } = blockInfo;
433	
434	            const nextBlockInfo = getNextBlockInfo(
435	              state.doc,
436	              blockInfo.bnBlock.beforePos,
437	            );
438	            if (!nextBlockInfo || !nextBlockInfo.isBlockContainer) {
439	              return false;
440	            }
441	
442	            const selectionAtBlockEnd =
443	              state.selection.from === blockContent.afterPos - 1;
444	            const selectionEmpty = state.selection.empty;
445	
446	            const posBetweenBlocks = blockContainer.afterPos;
447	
448	            if (selectionAtBlockEnd && selectionEmpty) {
449	              return chain()
450	                .command(mergeBlocksCommand(posBetweenBlocks))
451	                .scrollIntoView()
452	                .run();
453	            }
454	
455	            return false;
456	          }),
457	        // If the previous block is a columnList, moves the current block to
458	        // the end of the last column in it.
459	        () =>
460	          commands.command(({ state, tr, dispatch }) => {
461	            const blockInfo = getBlockInfoFromSelection(state);
462	            if (!blockInfo.isBlockContainer) {
463	              return false;
464	            }
465	
466	            const nextBlockInfo = getNextBlockInfo(
467	              state.doc,
468	              blockInfo.bnBlock.beforePos,
469	            );
470	            if (!nextBlockInfo || nextBlockInfo.isBlockContainer) {
471	              return false;
472	            }
473	
474	            if (dispatch) {
475	              const columnBeforePos = nextBlockInfo.bnBlock.beforePos + 1;
476	              const $blockBeforePos = tr.doc.resolve(columnBeforePos + 1);
477	
478	              tr.delete(
479	                $blockBeforePos.pos,
480	                $blockBeforePos.pos + $blockBeforePos.nodeAfter!.nodeSize,
481	              );
482	              fixColumnList(tr, nextBlockInfo.bnBlock.beforePos);
483	              tr.insert(blockInfo.bnBlock.afterPos, $blockBeforePos.nodeAfter!);
484	              tr.setSelection(
485	                TextSelection.near(tr.doc.resolve($blockBeforePos.pos)),
486	              );
487	
488	              return true;
489	            }
490	
491	            return false;
492	          }),
493	        // If the block is the last in a column, moves it to the start of the
494	        // next column. If there is no next column, moves it below the
495	        // columnList.
496	        () =>
497	          commands.command(({ state, tr, dispatch }) => {
498	            const blockInfo = getBlockInfoFromSelection(state);
499	            if (!blockInfo.isBlockContainer) {
500	              return false;
501	            }
502	
503	            const selectionAtBlockEnd =
504	              tr.selection.from === blockInfo.blockContent.afterPos - 1;
505	            if (!selectionAtBlockEnd) {
506	              return false;
507	            }
508	
509	            const $pos = tr.doc.resolve(blockInfo.bnBlock.afterPos);
510	
511	            const nextBlock = $pos.nodeAfter;
512	            if (nextBlock) {
513	              return false;
514	            }
515	
516	            const parentBlock = $pos.node();
517	            if (parentBlock.type.name !== "column") {
518	              return false;
519	            }
520	
521	            const $blockEndPos = tr.doc.resolve(blockInfo.bnBlock.afterPos);
522	            const $columnEndPos = tr.doc.resolve($blockEndPos.after());
523	            const columnListEndPos = $columnEndPos.after();
524	
525	            if (dispatch) {
526	              // Position before first block in next column, or first block
527	              // after columnList if there is no next column.
528	              const nextBlockBeforePos =
529	                $columnEndPos.pos === columnListEndPos - 1
530	                  ? columnListEndPos
531	                  : $columnEndPos.pos + 1;
532	              const nextBlockInfo = getBlockInfoFromResolvedPos(
533	                tr.doc.resolve(nextBlockBeforePos),
534	              );
535	
536	              tr.delete(
537	                nextBlockInfo.bnBlock.beforePos,
538	                nextBlockInfo.bnBlock.afterPos,
539	              );
540	              fixColumnList(
541	                tr,
542	                columnListEndPos - $columnEndPos.node().nodeSize,
543	              );
544	              tr.insert($blockEndPos.pos, nextBlockInfo.bnBlock.node);
545	              tr.setSelection(
546	                TextSelection.near(tr.doc.resolve(nextBlockBeforePos)),
547	              );
548	            }
549	
550	            return true;
551	          }),
552	        // Deletes the next block at either the same or lower nesting level, if
553	        // the selection is empty and at the end of the block. If both the
554	        // current and next blocks have inline content, the next block's
555	        // content is appended to the current block's. The next block's own
556	        // children are unindented before it's deleted.
557	        () =>
558	          commands.command(({ state }) => {
559	            const blockInfo = getBlockInfoFromSelection(state);
560	            if (!blockInfo.isBlockContainer) {
561	              return false;
562	            }
563	            const { blockContent } = blockInfo;
564	
565	            const selectionAtBlockEnd =
566	              state.selection.from === blockContent.afterPos - 1;
567	            const selectionEmpty = state.selection.empty;
568	
569	            if (selectionAtBlockEnd && selectionEmpty) {
570	              const getNextBlockInfoAtAnyLevel = (
571	                doc: Node,
572	                beforePos: number,
573	              ) => {
574	                const nextBlockInfo = getNextBlockInfo(doc, beforePos);
575	                if (nextBlockInfo) {
576	                  return nextBlockInfo;
577	                }
578	
579	                const parentBlockInfo = getParentBlockInfo(doc, beforePos);
580	                if (!parentBlockInfo) {
581	                  return undefined;
582	                }
583	
584	                return getNextBlockInfoAtAnyLevel(
585	                  doc,
586	                  parentBlockInfo.bnBlock.beforePos,
587	                );
588	              };
589	
590	              const nextBlockInfo = getNextBlockInfoAtAnyLevel(
591	                state.doc,
592	                blockInfo.bnBlock.beforePos,
593	              );
594	              if (!nextBlockInfo || !nextBlockInfo.isBlockContainer) {
595	                return false;
596	              }
597	
598	              const nextBlockContent = nextBlockInfo.blockContent.node;
599	              const nextBlockHasInlineContent =
600	                nextBlockContent.type.spec.content === "inline*";
601	              const blockHasInlineContent =
602	                blockContent.node.type.spec.content === "inline*";
603	
604	              return (
605	                chain()
606	                  // Un-nests next block's children if necessary.
607	                  .insertContentAt(
608	                    nextBlockInfo.bnBlock.afterPos,
609	                    nextBlockInfo.childContainer?.node.content ||
610	                      Fragment.empty,
611	                  )
612	                  .deleteRange({
613	                    from: nextBlockInfo.bnBlock.beforePos,
614	                    to: nextBlockInfo.bnBlock.afterPos,
615	                  })
616	                  // Appends inline content from child block if possible.
617	                  .insertContentAt(
618	                    state.selection.from,
619	                    nextBlockHasInlineContent && blockHasInlineContent
620	                      ? nextBlockContent.content
621	                      : null,
622	                  )
623	                  .setTextSelection(state.selection.from)
624	                  .scrollIntoView()
625	                  .run()
626	              );
627	            }
628	
629	            return false;
630	          }),
631	        // Deletes the current block if it's an empty block with inline content,
632	        // and moves the selection to the next block.
633	        () =>
634	          commands.command(({ state }) => {
635	            const blockInfo = getBlockInfoFromSelection(state);
636	            if (!blockInfo.isBlockContainer) {
637	              return false;
638	            }
639	
640	            const blockEmpty =
641	              blockInfo.blockContent.node.childCount === 0 &&
642	              blockInfo.blockContent.node.type.spec.content === "inline*";
643	
644	            if (blockEmpty) {
645	              const nextBlockInfo = getNextBlockInfo(
646	                state.doc,
647	                blockInfo.bnBlock.beforePos,
648	              );
649	              if (!nextBlockInfo || !nextBlockInfo.isBlockContainer) {
650	                return false;
651	              }
652	
653	              let chainedCommands = chain();
654	
655	              if (
656	                nextBlockInfo.blockContent.node.type.spec.content ===
657	                "tableRow+"
658	              ) {
659	                const tableBlockStartPos = blockInfo.bnBlock.afterPos + 1;
660	                const tableBlockContentStartPos = tableBlockStartPos + 1;
661	                const firstRowStartPos = tableBlockContentStartPos + 1;
662	                const firstCellStartPos = firstRowStartPos + 1;
663	                const firstCellParagraphStartPos = firstCellStartPos + 1;
664	
665	                chainedCommands = chainedCommands.setTextSelection(
666	                  firstCellParagraphStartPos,
667	                );
668	              } else if (
669	                nextBlockInfo.blockContent.node.type.spec.content === ""
670	              ) {
671	                chainedCommands = chainedCommands.setNodeSelection(
672	                  nextBlockInfo.blockContent.beforePos,
673	                );
674	              } else {
675	                chainedCommands = chainedCommands.setTextSelection(
676	                  nextBlockInfo.blockContent.beforePos + 1,
677	                );
678	              }
679	
680	              return chainedCommands
681	                .deleteRange({
682	                  from: blockInfo.bnBlock.beforePos,
683	                  to: blockInfo.bnBlock.afterPos,
684	                })
685	                .scrollIntoView()
686	                .run();
687	            }
688	
689	            return false;
690	          }),
691	        // Deletes next block if it contains no content and isn't a table,
692	        // when the selection is empty and at the end of the block. Moves the
693	        // current block into the deleted block's place.
694	        () =>
695	          commands.command(({ state }) => {
696	            const blockInfo = getBlockInfoFromSelection(state);
697	
698	            if (!blockInfo.isBlockContainer) {
699	              return false;
700	            }
701	
702	            const selectionAtBlockEnd =
703	              state.selection.from === blockInfo.blockContent.afterPos - 1;
704	            const selectionEmpty = state.selection.empty;
705	
706	            const nextBlockInfo = getNextBlockInfo(
707	              state.doc,
708	              blockInfo.bnBlock.beforePos,
709	            );
710	            if (!nextBlockInfo) {
711	              return false;
712	            }
713	            if (!nextBlockInfo.isBlockContainer) {
714	              return false;
715	            }
716	
717	            if (nextBlockInfo && selectionAtBlockEnd && selectionEmpty) {
718	              const nextBlockNotTableAndNoContent =
719	                nextBlockInfo.blockContent.node.type.spec.content === "" ||
720	                (nextBlockInfo.blockContent.node.type.spec.content ===
721	                  "inline*" &&
722	                  nextBlockInfo.blockContent.node.childCount === 0);
723	
724	              if (nextBlockNotTableAndNoContent) {
725	                const childBlocks =
726	                  nextBlockInfo.bnBlock.node.lastChild!.content;
727	                return chain()
728	                  .deleteRange({
729	                    from: nextBlockInfo.bnBlock.beforePos,
730	                    to: nextBlockInfo.bnBlock.afterPos,
731	                  })
732	                  .insertContentAt(
733	                    blockInfo.bnBlock.afterPos,
734	                    nextBlockInfo.bnBlock.node.childCount === 2
735	                      ? childBlocks
736	                      : null,
737	                  )
738	                  .run();
739	              }
740	            }
741	
742	            return false;
743	          }),
744	      ]);
745	
746	    const handleEnter = (withShift = false) => {
747	      return this.editor.commands.first(({ commands, tr }) => [
748	        // Removes a level of nesting if the block is empty & indented, while the selection is also empty & at the start
749	        // of the block.
750	        () =>
751	          commands.command(({ state }) => {
752	            const blockInfo = getBlockInfoFromSelection(state);
753	            if (!blockInfo.isBlockContainer) {
754	              return false;
755	            }
756	            const { bnBlock: blockContainer, blockContent } = blockInfo;
757	
758	            const { depth } = state.doc.resolve(blockContainer.beforePos);
759	
760	            const selectionAtBlockStart =
761	              state.selection.$anchor.parentOffset === 0;
762	            const selectionEmpty =
763	              state.selection.anchor === state.selection.head;
764	            const blockEmpty = blockContent.node.childCount === 0;
765	            const blockIndented = depth > 1;
766	
767	            if (
768	              selectionAtBlockStart &&
769	              selectionEmpty &&
770	              blockEmpty &&
771	              blockIndented
772	            ) {
773	              return commands.liftListItem("blockContainer");
774	            }
775	
776	            return false;
777	          }),
778	        // Creates a hard break if block is configured to do so.
779	        () =>
780	          commands.command(({ state }) => {
781	            const blockInfo = getBlockInfoFromSelection(state);
782	
783	            const blockHardBreakShortcut =
784	              this.options.editor.schema.blockSchema[
785	                blockInfo.blockNoteType as keyof typeof this.options.editor.schema.blockSchema
786	              ].meta?.hardBreakShortcut ?? "shift+enter";
787	
788	            if (blockHardBreakShortcut === "none") {
789	              return false;
790	            }
791	
792	            if (
793	              // If shortcut is not configured, or is configured as "shift+enter",
794	              // create a hard break for shift+enter, but not for enter.
795	              (blockHardBreakShortcut === "shift+enter" && withShift) ||
796	              // If shortcut is configured as "enter", create a hard break for
797	              // both enter and shift+enter.
798	              blockHardBreakShortcut === "enter"
799	            ) {
800	              const marks =
801	                tr.storedMarks ||
802	                tr.selection.$head
803	                  .marks()
804	                  .filter((m) =>
805	                    this.editor.extensionManager.splittableMarks.includes(
806	                      m.type.name,
807	                    ),
808	                  );
809	
810	              tr.insert(
811	                tr.selection.head,
812	                tr.doc.type.schema.nodes.hardBreak.create(),
813	              ).ensureMarks(marks);
814	              return true;
815	            }
816	
817	            return false;
818	          }),
819	        // Creates a new block and moves the selection to it if the current one is empty, while the selection is also
820	        // empty & at the start of the block.
821	        () =>
822	          commands.command(({ state, dispatch, tr }) => {
823	            const blockInfo = getBlockInfoFromSelection(state);
824	            if (!blockInfo.isBlockContainer) {
825	              return false;
826	            }
827	            const { bnBlock: blockContainer, blockContent } = blockInfo;
828	
829	            const selectionAtBlockStart =
830	              state.selection.$anchor.parentOffset === 0;
831	            const selectionEmpty =
832	              state.selection.anchor === state.selection.head;
833	            const blockEmpty = blockContent.node.childCount === 0;
834	
835	            if (selectionAtBlockStart && selectionEmpty && blockEmpty) {
836	              const newBlockInsertionPos = blockContainer.afterPos;
837	              const newBlockContentPos = newBlockInsertionPos + 2;
838	
839	              if (dispatch) {
840	                // Creates a new block with the children of the current block,
841	                // if it has any.
842	                const newBlock = state.schema.nodes[
843	                  "blockContainer"
844	                ].createAndFill(
845	                  undefined,
846	                  [
847	                    state.schema.nodes["paragraph"].createAndFill() ||
848	                      undefined,
849	                    blockInfo.childContainer?.node,
850	                  ].filter((node) => node !== undefined),
851	                )!;
852	
853	                // Inserts the new block and moves the selection to it.
854	                tr.insert(newBlockInsertionPos, newBlock)
855	                  .setSelection(
856	                    new TextSelection(tr.doc.resolve(newBlockContentPos)),
857	                  )
858	                  .scrollIntoView();
859	
860	                // Deletes old block's children, as they have been moved to
861	                // the new one.
862	                if (blockInfo.childContainer) {
863	                  tr.delete(
864	                    blockInfo.childContainer.beforePos,
865	                    blockInfo.childContainer.afterPos,
866	                  );
867	                }
868	              }
869	
870	              return true;
871	            }
872	
873	            return false;
874	          }),
875	        // Splits the current block, moving content inside that's after the cursor to a new text block below. Also
876	        // deletes the selection beforehand, if it's not empty.
877	        () =>
878	          commands.command(({ state, chain }) => {
879	            const blockInfo = getBlockInfoFromSelection(state);
880	            if (!blockInfo.isBlockContainer) {
881	              return false;
882	            }
883	            const { blockContent } = blockInfo;
884	
885	            const selectionAtBlockStart =
886	              state.selection.$anchor.parentOffset === 0;
887	            const blockEmpty = blockContent.node.childCount === 0;
888	
889	            if (!blockEmpty) {
890	              chain()
891	                .deleteSelection()
892	                .command(
893	                  splitBlockCommand(
894	                    state.selection.from,
895	                    selectionAtBlockStart,
896	                    selectionAtBlockStart,
897	                  ),
898	                )
899	                .run();
900	
901	              return true;
902	            }
903	
904	            return false;
905	          }),
906	      ]);
907	    };
908	
909	    return {
910	      Backspace: handleBackspace,
911	      Delete: handleDelete,
912	      Enter: () => handleEnter(),
