914	      // Always returning true for tab key presses ensures they're not captured by the browser. Otherwise, they blur the
915	      // editor since the browser will try to use tab for keyboard navigation.
916	      Tab: () => {
917	        if (
918	          this.options.tabBehavior !== "prefer-indent" &&
919	          (this.options.editor.getExtension(FormattingToolbarExtension)?.store
920	            .state ||
921	            this.options.editor.getExtension(FilePanelExtension)?.store
922	              .state !== undefined)
923	          // TODO need to check if the link toolbar is open or another alternative entirely
924	        ) {
925	          // don't handle tabs if a toolbar is shown, so we can tab into / out of it
926	          return false;
927	        }
928	        return nestBlock(this.options.editor);
929	      },
930	      "Shift-Tab": () => {
931	        if (
932	          this.options.tabBehavior !== "prefer-indent" &&
933	          (this.options.editor.getExtension(FormattingToolbarExtension)?.store
934	            .state ||
935	            this.options.editor.getExtension(FilePanelExtension)?.store
936	              .state !== undefined)
937	          // TODO need to check if the link toolbar is open or another alternative entirely
938	          // other menu types?
939	        ) {
940	          // don't handle tabs if a toolbar is shown, so we can tab into / out of it
941	          return false;
942	        }
943	        return this.editor.commands.liftListItem("blockContainer");
944	      },
945	      "Shift-Mod-ArrowUp": () => {
946	        this.options.editor.moveBlocksUp();
947	        return true;
948	      },
949	      "Shift-Mod-ArrowDown": () => {
950	        this.options.editor.moveBlocksDown();
951	        return true;
952	      },
953	      "Mod-z": () => this.options.editor.undo(),
